  ('real-estate-moex-02265', 'real-estate', 'real-estate-moex-099-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '依都市計畫法之規定，公園、體育場所、綠地、廣場及兒童遊樂場，應依計畫人口密度及自然環境，作有系統之布置，除具有 特殊情形外，其佔用土地總面積不得少於全部計畫面積之多少？', '["百分之五", "百分之十", "百分之二十", "百分之三十"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:11+00:00", "source_pdf_sha1": "9833770e63fc", "answer_pdf_sha1": "6c1dc0520ebc", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法與土地相關稅法概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 23, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02266', 'real-estate', 'real-estate-moex-099-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '依相關法條之規定，下列何者定需課土地增值稅？', '["兄弟相互贈與土地", "區段徵收之土地，以現金補償其地價者", "作農業使用之農業用地，移轉與自然人時", "依都市計畫法指定之公共設施保留地尚未被徵收前之移轉"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:11+00:00", "source_pdf_sha1": "9833770e63fc", "answer_pdf_sha1": "6c1dc0520ebc", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法與土地相關稅法概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 24, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02267', 'real-estate', 'real-estate-moex-099-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '依都市計畫法徵收或區段徵收之公共設施保留地，其地價補償以徵收當期毗鄰非公共設施保留地之平均公告土地現值為準，必 要時得加成補償之。但加成最高以不超過多少為限？', '["百分之十", "百分之二十", "百分之三十", "百分之四十"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:11+00:00", "source_pdf_sha1": "9833770e63fc", "answer_pdf_sha1": "6c1dc0520ebc", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法與土地相關稅法概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 25, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02268', 'real-estate', 'real-estate-moex-099-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '依土地法之規定，以現金為租賃之擔保者，其現金利息視為租金之一部，而該擔保之金額，不得超過幾個月房屋租金之總額？', '["1個月", "2個月", "3個月", "4個月"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:11+00:00", "source_pdf_sha1": "9833770e63fc", "answer_pdf_sha1": "6c1dc0520ebc", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法與土地相關稅法概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 26, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02269', 'real-estate', 'real-estate-moex-099-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '依平均地權條例之規定，在何種情況下得申請該管直轄市或縣（市）政府核准後優先實施市地重劃？', '["適當地區內之私有土地所有權人半數以上，而其所有土地面積超過區內私有土地總面積半數者之同意", "適當地區內之私有土地所有權人三分之二以上，而其所有土地面積超過區內私有土地總面積半數者之同意", "適當地區內之私有土地所有權人半數以上，而其所有土地面積超過區內私有土地總面積三分之二以上之同意", "適當地區內之私有土地所有權人三分之二以上，而其所有土地面積超過區內私有土地總面積三分之二以上之同意"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:11+00:00", "source_pdf_sha1": "9833770e63fc", "answer_pdf_sha1": "6c1dc0520ebc", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法與土地相關稅法概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 27, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02270', 'real-estate', 'real-estate-moex-099-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '被徵收之土地，除區段徵收及依土地徵收條例或其他法律另有規定外，在某些情形發生時，原土地所有權人得於徵收公告之日 起20年內，向該管直轄市或縣（市）主管機關申請照原徵收補償價額收回其土地，不適用土地法第219條之規定，下列敘述何 者錯誤？', '["徵收補償費發給完竣屆滿3年，未依徵收計畫開始使用者", "未依核准徵收原定興辦事業使用者", "經監察院糾正確定者", "依原徵收計畫開始使用後未滿5年，不繼續依原徵收計畫使用者"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:11+00:00", "source_pdf_sha1": "9833770e63fc", "answer_pdf_sha1": "6c1dc0520ebc", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法與土地相關稅法概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 28, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02271', 'real-estate', 'real-estate-moex-099-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '依土地稅法之規定，地價稅或田賦之納稅義務人，下列何者錯誤？', '["設有典權土地，為出典人", "承領土地，為承領人", "承墾土地，為耕作權人", "土地所有權人"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:11+00:00", "source_pdf_sha1": "9833770e63fc", "answer_pdf_sha1": "6c1dc0520ebc", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法與土地相關稅法概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 29, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
